/* ══════════════════════════════════════════════
   HELPERS
══════════════════════════════════════════════ */
const toKey = (d) => `${d.getFullYear()}-${p2(d.getMonth()+1)}-${p2(d.getDate())}`;
const todayKey = () => toKey(new Date());
const p2 = (n) => String(n).padStart(2,"0");
const fmtTime = (s) => `${p2(Math.floor(s/60))}:${p2(s%60)}`;
const fmtMins = (m) => { if(!m)return"0분"; const h=Math.floor(m/60),min=m%60; if(h===0)return`${min}분`; if(min===0)return`${h}시간`; return`${h}시간 ${min}분`; };
const isPastOrToday = (yr,mo,d) => { const t=new Date(); t.setHours(23,59,59,999); return new Date(yr,mo,d)<=t; };
const timeToMins = (t) => { const [h,m]=t.split(":").map(Number); return h*60+m; };
const calcDuration = (start, end) => {
  let d = timeToMins(end) - timeToMins(start);
  if (d < 0) d += 24*60;
  return d;
};

