/* ══════════════════════════════════════════════
   고미 CHARACTER SVG (Bear costume - warm brown)
══════════════════════════════════════════════ */
function GomiCharacter({ minutes, goal }) {
  const pct = goal > 0 ? Math.min(minutes / goal, 1) : 0;
  const SIZE = 180; // svg canvas
  const CX = SIZE/2, CY = SIZE/2;
  const R = 82; // ring radius — large & visible
  const circ = 2*Math.PI*R, dash = circ*pct;
  const IMG_SIZE = 100; // character image size (smaller)

  return (
    <div style={{ display:"flex", flexDirection:"column", alignItems:"center", paddingTop:8 }}>
      <div style={{ background:"linear-gradient(135deg,#B45309,#D97706)", color:"#fff", borderRadius:20, padding:"5px 18px", fontSize:13, fontWeight:700, marginBottom:6, boxShadow:"0 4px 16px rgba(180,83,9,0.3)", animation:"floatUp 3s ease-in-out infinite" }}>
        오늘 {minutes}분 수행{goal>0&&<span style={{opacity:0.75,fontWeight:400}}> / 목표 {fmtMins(goal)}</span>}
      </div>
      <div style={{ position:"relative", width:SIZE, height:SIZE, display:"flex", alignItems:"center", justifyContent:"center" }}>
        {/* Ring — always rendered when goal > 0, thick and clear */}
        {goal>0 ? (
          <svg width={SIZE} height={SIZE} style={{ position:"absolute", top:0, left:0 }}>
            {/* Track */}
            <circle cx={CX} cy={CY} r={R} fill="none" stroke="#FDE68A" strokeWidth="10"/>
            {/* Progress */}
            <circle cx={CX} cy={CY} r={R} fill="none" stroke="#D97706" strokeWidth="10"
              strokeDasharray={`${dash} ${circ}`} strokeLinecap="round"
              transform={`rotate(-90 ${CX} ${CY})`}
              style={{transition:"stroke-dasharray 0.6s ease"}}/>
            {/* Percentage text inside ring */}
            <text x={CX} y={CY+38} textAnchor="middle" fontSize="12" fill="#B45309" fontWeight="700">
              {Math.round(pct*100)}%
            </text>
          </svg>
        ) : (
          <svg width={SIZE} height={SIZE} style={{ position:"absolute", top:0, left:0 }}>
            <circle cx={CX} cy={CY} r={R} fill="none" stroke="#FEF3C7" strokeWidth="6" strokeDasharray="6 4"/>
          </svg>
        )}
        <img src={GOMI_IMG} alt="고미"
          style={{ width:IMG_SIZE, height:IMG_SIZE, objectFit:"contain", position:"relative", zIndex:1,
            filter:"drop-shadow(0 3px 10px rgba(180,83,9,0.18))" }}/>

        {/* Sparkles around character */}
        <svg width={SIZE} height={SIZE} style={{position:"absolute",top:0,left:0,pointerEvents:"none",zIndex:2}}>
          {[
            {cx:30, cy:42, r:3.5, delay:0,    color:"#FDE68A"},
            {cx:148,cy:38, r:2.5, delay:0.4,  color:"#F472B6"},
            {cx:22, cy:105,r:3,   delay:0.8,  color:"#D97706"},
            {cx:155,cy:100,r:2.5, delay:1.2,  color:"#FDE68A"},
            {cx:55, cy:25, r:2,   delay:1.6,  color:"#F472B6"},
            {cx:128,cy:28, r:3,   delay:2.0,  color:"#D97706"},
            {cx:18, cy:70, r:2,   delay:2.4,  color:"#FDE68A"},
            {cx:160,cy:65, r:2.5, delay:2.8,  color:"#F472B6"},
          ].map((s,i)=>(
            <g key={i}>
              <circle cx={s.cx} cy={s.cy} r={s.r} fill={s.color}
                style={{animation:`sparkleGomi 2.4s ${s.delay}s ease-in-out infinite`}}/>
              {/* Cross sparkle */}
              <line x1={s.cx-s.r*1.6} y1={s.cy} x2={s.cx+s.r*1.6} y2={s.cy}
                stroke={s.color} strokeWidth="1.2" strokeLinecap="round"
                style={{animation:`sparkleGomi 2.4s ${s.delay}s ease-in-out infinite`}}/>
              <line x1={s.cx} y1={s.cy-s.r*1.6} x2={s.cx} y2={s.cy+s.r*1.6}
                stroke={s.color} strokeWidth="1.2" strokeLinecap="round"
                style={{animation:`sparkleGomi 2.4s ${s.delay}s ease-in-out infinite`}}/>
            </g>
          ))}
        </svg>

      </div>
      <style>{`
        @keyframes floatUp{0%,100%{transform:translateY(0)}50%{transform:translateY(-5px)}}
        @keyframes sparkleGomi{
          0%{opacity:0;transform:scale(0.3)}
          30%{opacity:1;transform:scale(1.2)}
          60%{opacity:0.8;transform:scale(1)}
          100%{opacity:0;transform:scale(0.3)}
        }
      `}</style>
    </div>
  );
}

/* ══════════════════════════════════════════════
   범이 CHARACTER SVG (Tiger costume - orange)
══════════════════════════════════════════════ */
function BeomiCharacter({ size = 120 }) {
  return (
    <img src={BEOMI_IMG} alt="범이" style={{ width:size, height:size, objectFit:"contain", filter:"drop-shadow(0 3px 8px rgba(200,100,30,0.2))" }}/>
  );
}

/* ══════════════════════════════════════════════
   STATS CHART
══════════════════════════════════════════════ */
function StatsChart({ records, goal }) {
  const dayNames = ["일","월","화","수","목","금","토"];
  const last7 = Array.from({length:7},(_,i)=>{
    const d=new Date(); d.setDate(d.getDate()-(6-i));
    const key=toKey(d);
    return {label:dayNames[d.getDay()],date:d.getDate(),key,mins:records[key]?.practice||0,isToday:i===6};
  });
  const maxVal=Math.max(...last7.map(d=>d.mins),goal||30,1);
  const bW=28,gap=10,lP=10,cH=85,svgW=(bW+gap)*7-gap+lP*2;
  const now=new Date();
  const mKeys=Object.keys(records).filter(k=>k.startsWith(`${now.getFullYear()}-${p2(now.getMonth()+1)}`));
  const mTotal=mKeys.reduce((s,k)=>s+(records[k]?.practice||0),0);
  const aDays=mKeys.filter(k=>(records[k]?.practice||0)>0).length;
  const cTotal=mKeys.filter(k=>records[k]?.cheongsu?.morning||records[k]?.cheongsu?.evening).length;
  return (
    <div>
      <div style={{background:"#fff",borderRadius:14,padding:"14px 8px 10px",marginBottom:12,border:"1px solid #FEF3C7"}}>
        <p style={{color:"#92400E",fontSize:12,fontWeight:600,margin:"0 0 10px 4px"}}>최근 7일 수행 현황</p>
        <svg width="100%" viewBox={`0 0 ${svgW} ${cH+32}`} style={{overflow:"visible"}}>
          {goal>0&&<line x1={lP} y1={cH-(goal/maxVal)*cH} x2={svgW-lP} y2={cH-(goal/maxVal)*cH} stroke="#FCD34D" strokeWidth="1.5" strokeDasharray="4,3"/>}
          {last7.map((d,i)=>{
            const bH=Math.max((d.mins/maxVal)*cH,d.mins>0?4:0),x=lP+i*(bW+gap),y=cH-bH;
            return (<g key={d.key}>
              <rect x={x} y={y} width={bW} height={bH} rx={5} fill={d.isToday?"#B45309":"#FDE68A"}/>
              {d.mins>0&&<text x={x+bW/2} y={y-4} textAnchor="middle" fontSize="8" fill={d.isToday?"#92400E":"#D97706"} fontWeight="700">{fmtMins(d.mins)}</text>}
              <text x={x+bW/2} y={cH+14} textAnchor="middle" fontSize="10" fill={d.isToday?"#92400E":"#9896AA"} fontWeight={d.isToday?"700":"400"}>{d.label}</text>
              <text x={x+bW/2} y={cH+24} textAnchor="middle" fontSize="9" fill="#C9A87A">{d.date}</text>
            </g>);
          })}
        </svg>
        {goal>0&&<p style={{fontSize:10,color:"#D97706",margin:"0 0 0 4px"}}>— 목표 {fmtMins(goal)}</p>}
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8}}>
        {[["🕯️","이번달 수행",fmtMins(mTotal)],["📅","수행 일수",`${aDays}일`],["💧","청수",`${cTotal}일`]].map(([icon,label,val])=>(
          <div key={label} style={{background:"#fff",borderRadius:12,padding:"12px 8px",textAlign:"center",border:"1px solid #FEF3C7"}}>
            <div style={{fontSize:20,marginBottom:3}}>{icon}</div>
            <div style={{color:"#B45309",fontSize:15,fontWeight:800}}>{val}</div>
            <div style={{color:"#C9A87A",fontSize:10,marginTop:1}}>{label}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

/* ══════════════════════════════════════════════
   CALENDAR (shared)
══════════════════════════════════════════════ */
function CalGrid({ records, onSelectDate, dotRenderer, accentColor="#B45309", accentBg="#FEF3C7" }) {
  const [calDate, setCalDate] = useState(new Date());
  const yr=calDate.getFullYear(), mo=calDate.getMonth();
  const firstDay=new Date(yr,mo,1).getDay(), dim=new Date(yr,mo+1,0).getDate();
  const today=new Date();
  const dNames=["일","월","화","수","목","금","토"];
  const mNames=["1월","2월","3월","4월","5월","6월","7월","8월","9월","10월","11월","12월"];
  const days=[]; for(let i=0;i<firstDay;i++) days.push(null); for(let d=1;d<=dim;d++) days.push(d);
  return (
    <div style={{background:"#fff",borderRadius:16,padding:14,border:`1px solid ${accentBg}`}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
        <button onClick={()=>setCalDate(new Date(yr,mo-1,1))} style={{background:"none",border:"none",color:accentColor,fontSize:22,cursor:"pointer",padding:"0 8px"}}>‹</button>
        <span style={{color:accentColor,fontWeight:700,fontSize:15}}>{yr}년 {mNames[mo]}</span>
        <button onClick={()=>setCalDate(new Date(yr,mo+1,1))} style={{background:"none",border:"none",color:accentColor,fontSize:22,cursor:"pointer",padding:"0 8px"}}>›</button>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",marginBottom:4}}>
        {dNames.map((d,i)=><div key={d} style={{textAlign:"center",fontSize:10,padding:"2px 0",color:i===0?"#EF4444":i===6?"#3B82F6":"#9896AA"}}>{d}</div>)}
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:2}}>
        {days.map((d,i)=>{
          if(!d) return <div key={`e${i}`}/>;
          const key=`${yr}-${p2(mo+1)}-${p2(d)}`;
          const rec=records[key];
          const isToday=d===today.getDate()&&mo===today.getMonth()&&yr===today.getFullYear();
          const isFuture=!isPastOrToday(yr,mo,d);
          return (
            <div key={key} onClick={()=>{ if(!isFuture&&onSelectDate) onSelectDate(new Date(yr,mo,d)); }}
              style={{borderRadius:8,padding:"3px 1px",textAlign:"center",
                background:isToday?accentBg:isFuture?"transparent":"transparent",
                border:`1.5px solid ${isToday?accentColor:"transparent"}`,
                minHeight:44,display:"flex",flexDirection:"column",alignItems:"center",
                cursor:isFuture?"not-allowed":"pointer",
                opacity:isFuture?0.3:1,
              }}>
              <span style={{fontSize:11,color:isToday?accentColor:"#6B7280",fontWeight:isToday?"700":"400"}}>{d}</span>
              {dotRenderer ? dotRenderer(rec, key) : (
                <>
                  {rec?.practice>0&&<span style={{fontSize:8,background:accentColor,color:"#fff",borderRadius:3,padding:"1px 3px",fontWeight:700,marginTop:1}}>{fmtMins(rec.practice)}</span>}
                  {(rec?.cheongsu?.morning||rec?.cheongsu?.evening)&&<span style={{fontSize:10,marginTop:1}}>💧</span>}
                  {rec?.baerae>0&&<span style={{fontSize:9,color:"#8B5CF6",marginTop:1}}>🙏{rec.baerae}</span>}
                </>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

/* ══════════════════════════════════════════════
   DATE RECORD MODAL
══════════════════════════════════════════════ */
function RecordModal({ date, record, onSave, onClose }) {
  const [p, setP]=useState(String(record?.practice??"")), [b, setB]=useState(String(record?.baerae??""));
  const [cM, setCM]=useState(record?.cheongsu?.morning??false), [cE, setCE]=useState(record?.cheongsu?.evening??false);
  const ds=`${date.getFullYear()}년 ${date.getMonth()+1}월 ${date.getDate()}일`;
  return (
    <div style={{position:"fixed",inset:0,zIndex:200,display:"flex",alignItems:"flex-end",justifyContent:"center"}}>
      <div onClick={onClose} style={{position:"absolute",inset:0,background:"rgba(0,0,0,0.3)"}}/>
      <div style={{position:"relative",background:"#fff",width:"100%",maxWidth:480,borderRadius:"24px 24px 0 0",padding:"24px 20px 40px",zIndex:1}}>
        <div style={{width:40,height:4,background:"#E5E7EB",borderRadius:2,margin:"0 auto 18px"}}/>
        <h3 style={{color:"#B45309",fontSize:15,fontWeight:700,margin:"0 0 16px",textAlign:"center"}}>📅 {ds} 기록 수정</h3>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:12}}>
          {[["수행(분)",p,setP],["배례(회)",b,setB]].map(([label,val,set])=>(
            <div key={label}><label style={LS}>{label}</label><input type="number" value={val} onChange={e=>set(e.target.value)} placeholder="0" style={{...IS,border:"1.5px solid #FEF3C7"}}/></div>
          ))}
        </div>
        <label style={{...LS,marginBottom:8}}>청수</label>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:16}}>
          {[["morning","🌅 아침",cM,setCM],["evening","🌙 저녁",cE,setCE]].map(([k,label,val,set])=>(
            <button key={k} onClick={()=>set(!val)} style={{padding:12,borderRadius:12,cursor:"pointer",background:val?"#FEF3C7":"#F9FAFB",border:`1.5px solid ${val?"#B45309":"#E5E7EB"}`,display:"flex",flexDirection:"column",alignItems:"center",gap:3}}>
              <span style={{fontSize:20}}>💧</span>
              <span style={{fontSize:12,color:val?"#B45309":"#9CA3AF"}}>{label}</span>
              {val&&<span style={{fontSize:10,color:"#059669"}}>✓</span>}
            </button>
          ))}
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
          <button onClick={onClose} style={{...BS,background:"#F3F4F6",color:"#6B7280",border:"none"}}>취소</button>
          <button onClick={()=>{onSave({practice:parseInt(p)||0,baerae:parseInt(b)||0,cheongsu:{morning:cM,evening:cE}});onClose();}} style={{...BS,background:"#B45309",color:"#fff",border:"none"}}>저장</button>
        </div>
      </div>
    </div>
  );
}

/* ══════════════════════════════════════════════
   기록 TAB
══════════════════════════════════════════════ */
function KirokTab({ records, onUpdateRecord, goal }) {
  const [selDate, setSelDate]=useState(new Date());
  const [addP, setAddP]=useState(""), [addB, setAddB]=useState("");
  const [saved, setSaved]=useState(false), [editModal, setEditModal]=useState(null);
  const selKey=toKey(selDate), isToday=selKey===todayKey();
  const rec=records[selKey]||{practice:0,baerae:0,cheongsu:{morning:false,evening:false}};
  const t=T["기록"];
  const handleAdd=async()=>{
    const pv=parseInt(addP)||0, bv=parseInt(addB)||0;
    if(!pv&&!bv) return;
    await onUpdateRecord(selKey,{...rec,practice:rec.practice+pv,baerae:rec.baerae+bv});
    setAddP(""); setAddB(""); setSaved(true); setTimeout(()=>setSaved(false),2000);
  };
  return (
    <div style={{background:t.bg,minHeight:"100vh",padding:"0 16px 100px"}}>
      <div style={{display:"flex",flexDirection:"column",alignItems:"center",paddingTop:20,paddingBottom:4}}>
        <GomiCharacter minutes={rec.practice} goal={isToday?goal:0}/>
      </div>
      {/* Date selector */}
      <div style={{marginBottom:14}}>
        <div style={{display:"flex",alignItems:"center",gap:10,background:"#fff",borderRadius:14,padding:"10px 14px",border:"1px solid #FEF3C7"}}>
          <span style={{fontSize:14,color:t.accent}}>📅</span>
          <span style={{flex:1,color:t.accentD,fontSize:14,fontWeight:600}}>{isToday?"오늘":`${selDate.getFullYear()}.${p2(selDate.getMonth()+1)}.${p2(selDate.getDate())}`}</span>
          <input type="date" value={selKey} onChange={e=>{const d=new Date(e.target.value+"T00:00:00");setSelDate(d);}}
            style={{border:"none",outline:"none",color:t.accent,fontSize:13,background:"transparent",cursor:"pointer"}}/>
        </div>
      </div>
      <Sec title="수행했어요" bg={t.accentL} bc={t.accent}>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:12}}>
          {[["🕯️","수행",fmtMins(rec.practice)],["🙏","배례",`${rec.baerae}회`]].map(([icon,label,val])=>(
            <div key={label} style={{display:"flex",alignItems:"center",justifyContent:"space-between",background:"#fff",borderRadius:12,padding:"14px 16px",border:`1px solid ${t.accent}22`}}>
              <div style={{display:"flex",flexDirection:"column",gap:4}}>
                <span style={{fontSize:22}}>{icon}</span>
                <span style={{color:"#9896AA",fontSize:12,fontWeight:500}}>{label}</span>
              </div>
              <span style={{color:t.accent,fontSize:30,fontWeight:800,letterSpacing:-1}}>{val}</span>
            </div>
          ))}
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:10}}>
          {[["수행 추가(분)",addP,setAddP],["배례 추가(회)",addB,setAddB]].map(([label,val,set])=>(
            <div key={label}><label style={LS}>{label}</label><input type="number" value={val} onChange={e=>set(e.target.value)} placeholder="0" style={{...IS,border:`1.5px solid ${t.accentL}`}}/></div>
          ))}
        </div>
        <button onClick={handleAdd} style={{...BS,background:t.accent,color:"#fff",border:"none",width:"100%"}}>{saved?"✅ 저장됐어요!":"+ 기록 추가"}</button>
      </Sec>
      <Sec title="청수" bg="#EFF6FF" bc="#60A5FA">
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
          {[["morning","☀️ 아침"],["evening","🌙 저녁"]].map(([key,label])=>(
            <button key={key} onClick={()=>onUpdateRecord(selKey,{...rec,cheongsu:{...rec.cheongsu,[key]:!rec.cheongsu?.[key]}})}
              style={{padding:"14px 12px",borderRadius:14,cursor:"pointer",background:rec.cheongsu?.[key]?"#DBEAFE":"#F8FAFC",border:`1.5px solid ${rec.cheongsu?.[key]?"#3B82F6":"#E0E7FF"}`,display:"flex",flexDirection:"column",alignItems:"center",gap:4}}>
              <span style={{fontSize:24}}>💧</span>
              <span style={{fontSize:13,color:rec.cheongsu?.[key]?"#1D4ED8":"#94A3B8"}}>{label}</span>
              {rec.cheongsu?.[key]&&<span style={{fontSize:11,color:"#059669"}}>✓ 완료</span>}
            </button>
          ))}
        </div>
      </Sec>
      <Sec title="📊 수행 통계" bg="#F5F0FF" bc="#7C3AED"><StatsChart records={records} goal={goal}/></Sec>
      <Sec title="📅 수행 달력" bg={t.accentL} bc={t.accent}>
        <p style={{color:"#9896AA",fontSize:12,margin:"0 0 10px"}}>날짜를 탭하면 기록을 수정할 수 있어요</p>
        <CalGrid records={records} onSelectDate={d=>{setSelDate(d);setEditModal(d);}} accentColor={t.accent} accentBg={t.accentL}/>
      </Sec>
      {editModal&&<RecordModal date={editModal} record={records[toKey(editModal)]||{}} onSave={r=>onUpdateRecord(toKey(editModal),r)} onClose={()=>setEditModal(null)}/>}
    </div>
  );
}

/* ══════════════════════════════════════════════
   체험일지 TAB
══════════════════════════════════════════════ */
const MOOD_EMOJI={기쁨:"😊",즐거움:"😄",평온:"😌",감사:"🙏",우울:"😔",화남:"😤",아픔:"🤒",피곤:"🥱",불안:"😰",설렘:"🥰"};
const getEntries=(j)=>{
  if(!j) return [];
  if(j.entries) return j.entries;
  // 레거시 단일 엔트리 변환
  return [{id:1,...j,moods:j.mood?[j.mood]:[]}];
};

function JournalTab({ journals, onSaveJournal }) {
  const [selDate, setSelDate]=useState(new Date());
  const [showEditor, setShowEditor]=useState(false);
  const [editEntry, setEditEntry]=useState(null); // null=new, object=edit
  const [viewMode, setViewMode]=useState("calendar");
  const t=T["체험일지"];
  const selKey=toKey(selDate);
  const entries=getEntries(journals[selKey]);
  const isToday=selKey===todayKey();

  const handleSave=(entryData)=>{
    const existing=getEntries(journals[selKey]);
    let updated;
    if(editEntry?.id) {
      updated=existing.map(e=>e.id===editEntry.id?{...e,...entryData}:e);
    } else {
      updated=[...existing,{id:Date.now(),...entryData}];
    }
    onSaveJournal(selKey,{entries:updated});
    setShowEditor(false); setEditEntry(null);
  };

  const handleDelete=(id)=>{
    const updated=getEntries(journals[selKey]).filter(e=>e.id!==id);
    onSaveJournal(selKey,{entries:updated});
  };

  const dotRenderer=(rec,key)=>{
    const ents=getEntries(journals[key]);
    return (
      <>
        {ents.length>0&&<div style={{width:6,height:6,borderRadius:"50%",background:t.accent,marginTop:2}}/>}
        {ents.length>1&&<span style={{fontSize:8,color:t.accent,fontWeight:700}}>{ents.length}</span>}
      </>
    );
  };

  return (
    <div style={{background:t.bg,minHeight:"100vh",padding:"0 16px 100px"}}>
      <div style={{display:"flex",alignItems:"center",gap:14,padding:"18px 0 8px"}}>
        <div style={{flexShrink:0}}><BeomiCharacter size={70}/></div>
        <div>
          <h2 style={{color:t.accentD,fontSize:17,fontWeight:800,margin:"0 0 4px"}}>체험일지</h2>
          <p style={{color:t.accent,fontSize:12,margin:0}}>수행 경험을 기록하고 돌아봐요 🌿</p>
        </div>
      </div>

      {/* Date selector */}
      <div style={{display:"flex",alignItems:"center",gap:8,background:"#fff",borderRadius:14,padding:"10px 14px",border:"1px solid #CCFBF1",marginBottom:12}}>
        <span style={{fontSize:14,color:t.accent}}>📅</span>
        <span style={{flex:1,color:t.accentD,fontSize:14,fontWeight:600}}>
          {isToday?"오늘":`${selDate.getFullYear()}.${p2(selDate.getMonth()+1)}.${p2(selDate.getDate())}`}
        </span>
        <input type="date" value={selKey}
          max={todayKey()}
          onChange={e=>{const d=new Date(e.target.value+"T00:00:00");setSelDate(d);setViewMode("entry");}}
          style={{border:"none",outline:"none",color:t.accent,fontSize:13,background:"transparent",cursor:"pointer"}}/>
      </div>

      {/* View toggle */}
      <div style={{display:"flex",gap:8,marginBottom:14}}>
        {[["calendar","📅 달력보기"],["entry","📔 일지보기"]].map(([mode,label])=>(
          <button key={mode} onClick={()=>setViewMode(mode)} style={{flex:1,padding:"9px",borderRadius:12,cursor:"pointer",fontWeight:600,fontSize:13,border:`1.5px solid ${viewMode===mode?t.accent:"#CCFBF1"}`,background:viewMode===mode?t.accentL:"#fff",color:viewMode===mode?t.accentD:"#9896AA"}}>
            {label}
          </button>
        ))}
      </div>

      {/* 일지 보기 */}
      {viewMode==="entry"&&(
        <Sec title={`${isToday?"오늘":"선택한 날짜"} 일지 (${entries.length}개)`} bg="#fff" bc={t.accent}>
          {entries.length===0 ? (
            <div style={{textAlign:"center",padding:"20px 0"}}>
              <p style={{color:"#9896AA",fontSize:14,marginBottom:14}}>아직 작성된 일지가 없어요</p>
            </div>
          ) : entries.map((e,i)=>(
            <div key={e.id} style={{background:t.bg,borderRadius:12,padding:14,marginBottom:10,border:`1px solid ${t.accentL}`}}>
              <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
                <span style={{fontSize:12,fontWeight:700,color:t.accent}}>#{i+1}</span>
                {e.startTime&&(
                  <span style={{fontSize:12,background:t.accentL,color:t.accentD,borderRadius:6,padding:"2px 8px",fontWeight:600}}>
                    ⏰ {e.startTime}~{e.endTime} · {fmtMins(e.duration)}
                  </span>
                )}
                <div style={{marginLeft:"auto",display:"flex",gap:6}}>
                  <button onClick={()=>{setEditEntry(e);setShowEditor(true);}} style={{background:"none",border:"none",cursor:"pointer",fontSize:14,color:t.accent}}>✏️</button>
                  <button onClick={()=>handleDelete(e.id)} style={{background:"none",border:"none",cursor:"pointer",fontSize:14,color:"#EF4444"}}>🗑️</button>
                </div>
              </div>
              {e.moods?.length>0&&(
                <div style={{display:"flex",gap:4,flexWrap:"wrap",marginBottom:6}}>
                  {e.moods.map(m=><span key={m} style={{fontSize:12}}>{MOOD_EMOJI[m]||""} {m}</span>)}
                </div>
              )}
              {e.diary&&<p style={{color:"#374151",fontSize:13,lineHeight:1.75,margin:0,whiteSpace:"pre-wrap"}}>{e.diary}</p>}
            </div>
          ))}
          <button onClick={()=>{setEditEntry(null);setShowEditor(true);}} style={{...BS,background:t.accent,color:"#fff",border:"none",width:"100%",marginTop:4}}>
            + 일지 추가하기
          </button>
        </Sec>
      )}

      {/* 달력 보기 */}
      {viewMode==="calendar"&&(
        <Sec title="📅 일지 달력" bg={t.accentL} bc={t.accent}>
          <p style={{color:"#9896AA",fontSize:12,margin:"0 0 10px"}}>날짜를 탭하면 해당 날 일지를 확인할 수 있어요</p>
          <CalGrid records={journals} onSelectDate={d=>{setSelDate(d);setViewMode("entry");}}
            dotRenderer={dotRenderer} accentColor={t.accent} accentBg={t.accentL}/>
        </Sec>
      )}

      {showEditor&&(
        <JournalEditor date={selDate} entry={editEntry}
          onSave={handleSave} onClose={()=>{setShowEditor(false);setEditEntry(null);}} t={t}/>
      )}
    </div>
  );
}

function JournalEditor({ date, entry, onSave, onClose, t }) {
  const [startTime, setStartTime]=useState(entry?.startTime||"06:00");
  const [endTime, setEndTime]=useState(entry?.endTime||"07:00");
  const [diary, setDiary]=useState(entry?.diary||"");
  const [moods, setMoods]=useState(entry?.moods||[]);
  const MOODS=[
    {key:"기쁨",  emoji:"😊", color:"#F59E0B"},
    {key:"즐거움", emoji:"😄", color:"#10B981"},
    {key:"평온",  emoji:"😌", color:"#6366F1"},
    {key:"감사",  emoji:"🙏", color:"#8B5CF6"},
    {key:"우울",  emoji:"😔", color:"#6B7280"},
    {key:"화남",  emoji:"😤", color:"#EF4444"},
    {key:"아픔",  emoji:"🤒", color:"#F97316"},
    {key:"피곤",  emoji:"🥱", color:"#A78BFA"},
    {key:"불안",  emoji:"😰", color:"#0EA5E9"},
    {key:"설렘",  emoji:"🥰", color:"#EC4899"},
  ];
  const toggleMood=(key)=>setMoods(prev=>prev.includes(key)?prev.filter(m=>m!==key):[...prev,key]);
  const duration=calcDuration(startTime, endTime);
  const ds=`${date.getFullYear()}년 ${date.getMonth()+1}월 ${date.getDate()}일`;
  return (
    <div style={{position:"fixed",inset:0,zIndex:200,display:"flex",alignItems:"flex-end",justifyContent:"center"}}>
      <div onClick={onClose} style={{position:"absolute",inset:0,background:"rgba(0,0,0,0.35)"}}/>
      <div style={{position:"relative",background:"#fff",width:"100%",maxWidth:480,borderRadius:"24px 24px 0 0",padding:"24px 20px 44px",zIndex:1,maxHeight:"90vh",overflowY:"auto"}}>
        <div style={{width:40,height:4,background:"#E5E7EB",borderRadius:2,margin:"0 auto 18px"}}/>
        <h3 style={{color:t.accentD,fontSize:16,fontWeight:700,margin:"0 0 18px",textAlign:"center"}}>📔 {ds} 일지</h3>

        {/* Time */}
        <Sec title="⏰ 수행 시간" bg={t.accentL} bc={t.accent}>
          <div style={{display:"grid",gridTemplateColumns:"1fr auto 1fr",alignItems:"center",gap:8,marginBottom:10}}>
            <div>
              <label style={LS}>시작 시간</label>
              <input type="time" value={startTime} onChange={e=>setStartTime(e.target.value)}
                style={{...IS,border:`1.5px solid ${t.accentL}`,textAlign:"center"}}/>
            </div>
            <span style={{color:t.accent,fontSize:18,fontWeight:700,marginTop:16}}>→</span>
            <div>
              <label style={LS}>종료 시간</label>
              <input type="time" value={endTime} onChange={e=>setEndTime(e.target.value)}
                style={{...IS,border:`1.5px solid ${t.accentL}`,textAlign:"center"}}/>
            </div>
          </div>
          <div style={{background:t.accent,borderRadius:10,padding:"10px 16px",textAlign:"center"}}>
            <span style={{color:"#fff",fontWeight:700,fontSize:15}}>
              총 수행 시간 : {fmtMins(duration)}
            </span>
          </div>
        </Sec>

        {/* Mood */}
        <Sec title="🌈 오늘의 컨디션 / 기분" bg={t.accentL} bc={t.accent}>
          <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:8}}>
            {MOODS.map(m=>{
              const sel=moods.includes(m.key);
              return (
                <button key={m.key} onClick={()=>toggleMood(m.key)}
                  style={{padding:"8px 4px",borderRadius:12,cursor:"pointer",border:`2px solid ${sel?m.color:"transparent"}`,background:sel?`${m.color}18`:"#fff",display:"flex",flexDirection:"column",alignItems:"center",gap:3,transition:"all 0.15s"}}>
                  <span style={{fontSize:22}}>{m.emoji}</span>
                  <span style={{fontSize:10,color:sel?m.color:"#9896AA",fontWeight:sel?700:400}}>{m.key}</span>
                </button>
              );
            })}
          </div>
        </Sec>

        {/* Diary */}
        <Sec title="✍️ 수행 일지" bg="#FAFAFA" bc={t.accent}>
          <textarea
            value={diary}
            onChange={e=>setDiary(e.target.value)}
            placeholder="오늘 수행을 하며 느낀 점, 경험, 감사한 일들을 자유롭게 기록해보세요..."
            style={{width:"100%",minHeight:140,padding:"12px 14px",borderRadius:12,border:`1.5px solid ${t.accentL}`,background:"#fff",color:"#374151",fontSize:14,lineHeight:1.8,resize:"vertical",outline:"none",boxSizing:"border-box",fontFamily:"'Noto Sans KR',sans-serif"}}
          />
        </Sec>

        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
          <button onClick={onClose} style={{...BS,background:"#F3F4F6",color:"#6B7280",border:"none"}}>취소</button>
          <button onClick={()=>onSave({startTime,endTime,duration,diary,moods})} style={{...BS,background:t.accent,color:"#fff",border:"none"}}>저장</button>
        </div>
      </div>
    </div>
  );
}

/* ══════════════════════════════════════════════
   말씀 TAB
══════════════════════════════════════════════ */
function MalssеumTab({ favorites, onToggleFavorite }) {
  const [sub, setSub]=useState("오늘의 말씀"), [cat, setCat]=useState("전체");
  const [searchQ, setSearchQ]=useState("");
  const dayIdx=Math.floor((Date.now()-new Date(new Date().getFullYear(),0,1))/86400000);
  const todayQ=QUOTES[dayIdx%QUOTES.length];
  const filtered=QUOTES.filter(q=>{
    const matchCat=cat==="전체"||q.category===cat;
    const matchQ=!searchQ||q.text.includes(searchQ)||q.source.includes(searchQ)||q.category.includes(searchQ);
    return matchCat&&matchQ;
  });
  const CAT_COLOR={"도전성구":"#7C3AED","태상종도사님":"#B45309","종도사님":"#0D9488"};
  const t=T["말씀"];

  return (
    <div style={{background:t.bg,minHeight:"100vh",padding:"0 16px 100px"}}>
      <div style={{display:"flex",gap:8,paddingTop:16,paddingBottom:4}}>
        {["오늘의 말씀","말씀 목록","즐겨찾기"].map(tab=>(
          <button key={tab} onClick={()=>setSub(tab)} style={{padding:"7px 14px",borderRadius:20,fontSize:13,cursor:"pointer",fontWeight:500,whiteSpace:"nowrap",background:sub===tab?t.accent:"#fff",color:sub===tab?"#fff":"#9896AA",border:`1px solid ${sub===tab?t.accent:"#EDE9FE"}`}}>{tab}</button>
        ))}
      </div>

      {sub==="오늘의 말씀"&&(
        <div style={{paddingTop:16}}>
          {/* Square centered quote box */}
          <div style={{
            aspectRatio:"1/1",
            background:"linear-gradient(145deg, #EDE9FE 0%, #DDD6FE 35%, #E0F2FE 70%, #EDE9FE 100%)",
            border:`2.5px solid ${t.accent}`,
            borderRadius:20,
            display:"flex",
            flexDirection:"column",
            alignItems:"center",
            justifyContent:"center",
            padding:"28px 24px",
            position:"relative",
            boxShadow:`0 8px 32px ${t.accent}30`,
            marginBottom:14,
          }}>
            {/* Corner decorations */}
            <span style={{position:"absolute",top:14,left:16,fontSize:18,opacity:0.35}}>✦</span>
            <span style={{position:"absolute",top:14,right:16,fontSize:18,opacity:0.35}}>✦</span>
            <span style={{position:"absolute",bottom:14,left:16,fontSize:18,opacity:0.35}}>✦</span>
            <span style={{position:"absolute",bottom:14,right:16,fontSize:18,opacity:0.35}}>✦</span>
            {/* Category badge */}
            <span style={{fontSize:11,background:t.accentL,color:t.accentD,borderRadius:20,padding:"3px 12px",fontWeight:700,marginBottom:18,border:`1px solid ${t.accent}44`}}>
              {todayQ.category}
            </span>
            {/* Quote text — large, centered */}
            <p style={{
              color:"#2D1B69",
              fontSize:18,
              fontWeight:700,
              lineHeight:1.9,
              fontFamily:"'Noto Serif KR','Noto Sans KR',serif",
              textAlign:"center",
              margin:"0 0 18px",
              letterSpacing:0.3,
            }}>{todayQ.text}</p>
            {/* Source */}
            <p style={{color:t.accent,fontSize:12,fontWeight:600,margin:0,opacity:0.85}}>{todayQ.source}</p>
            {/* Favorite button */}
            <button onClick={()=>onToggleFavorite(todayQ.id)}
              style={{position:"absolute",top:14,right:46,background:"none",border:"none",fontSize:20,cursor:"pointer"}}>
              {favorites.includes(todayQ.id)?"⭐":"☆"}
            </button>
          </div>
        </div>
      )}

      {sub==="말씀 목록"&&(
        <div style={{paddingTop:12}}>
          {/* 검색창 */}
          <div style={{position:"relative",marginBottom:12}}>
            <span style={{position:"absolute",left:12,top:"50%",transform:"translateY(-50%)",fontSize:14,color:t.accent}}>🔍</span>
            <input type="text" placeholder="말씀 검색..." value={searchQ} onChange={e=>setSearchQ(e.target.value)}
              style={{width:"100%",padding:"10px 12px 10px 36px",borderRadius:12,border:`1.5px solid ${t.accentL}`,background:"#fff",fontSize:14,outline:"none",boxSizing:"border-box"}}/>
            {searchQ&&<button onClick={()=>setSearchQ("")} style={{position:"absolute",right:10,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",cursor:"pointer",color:"#9896AA",fontSize:16}}>✕</button>}
          </div>
          <div style={{display:"flex",gap:6,marginBottom:12,flexWrap:"wrap"}}>
            {CATS.map(c=>{
              const cc=CAT_COLOR[c]||t.accent;
              return (
                <button key={c} onClick={()=>setCat(c)} style={{padding:"5px 14px",borderRadius:16,fontSize:12,cursor:"pointer",fontWeight:cat===c?700:400,background:cat===c?cc:"#fff",color:cat===c?"#fff":"#9896AA",border:`1.5px solid ${cat===c?cc:"#EDE9FE"}`}}>{c}</button>
              );
            })}
          </div>
          {filtered.map(q=>{
            const cc=CAT_COLOR[q.category]||t.accent;
            return (
              <div key={q.id} style={{background:"#fff",borderRadius:14,padding:16,border:`1.5px solid ${cc}22`,marginBottom:10,position:"relative"}}>
                <div style={{display:"flex",alignItems:"flex-start",gap:8,marginBottom:8}}>
                  <span style={{fontSize:10,background:`${cc}18`,color:cc,borderRadius:5,padding:"2px 8px",flexShrink:0,fontWeight:600,border:`1px solid ${cc}33`}}>{q.category}</span>
                  <button onClick={()=>onToggleFavorite(q.id)} style={{marginLeft:"auto",background:"none",border:"none",cursor:"pointer",fontSize:16,padding:2}}>
                    {favorites.includes(q.id)?"⭐":"☆"}
                  </button>
                </div>
                <p style={{color:"#3D2B6B",fontSize:14,lineHeight:1.75,fontFamily:"'Noto Serif KR','Noto Sans KR',serif",margin:"0 0 6px"}}>{q.text}</p>
                <p style={{color:cc,fontSize:11,margin:0,opacity:0.8}}>{q.source}</p>
              </div>
            );
          })}
        </div>
      )}
      {sub==="즐겨찾기"&&(
        <div style={{paddingTop:12}}>
          {QUOTES.filter(q=>favorites.includes(q.id)).length===0
            ?<p style={{color:"#A78BFA",textAlign:"center",padding:40}}>⭐ 즐겨찾기한 말씀이 없습니다</p>
            :QUOTES.filter(q=>favorites.includes(q.id)).map(q=>(
              <div key={q.id} style={{background:"#fff",borderRadius:14,padding:16,border:`1px solid ${t.accentL}`,marginBottom:10,position:"relative"}}>
                <span style={{fontSize:10,background:t.accentL,color:t.accentD,borderRadius:5,padding:"2px 7px"}}>{q.category}</span>
                <button onClick={()=>onToggleFavorite(q.id)} style={{position:"absolute",top:14,right:14,background:"none",border:"none",cursor:"pointer",fontSize:18}}>⭐</button>
                <p style={{color:"#3D2B6B",fontSize:14,lineHeight:1.7,fontFamily:"'Noto Serif KR','Noto Sans KR',serif",margin:"8px 0 5px"}}>{q.text}</p>
                <p style={{color:"#A78BFA",fontSize:12,margin:0}}>{q.source}</p>
              </div>
            ))
          }
        </div>
      )}
    </div>
  );
}

/* ══════════════════════════════════════════════
   수행가이드 TAB (주문 섹션 제거, 타이머 목표 추가)
══════════════════════════════════════════════ */
function SuhaengTab({ records, onUpdateRecord }) {
  const [lv, setLv]=useState(0), [sec, setSec]=useState(0), [running, setRunning]=useState(false);
  const [timerSaved, setTimerSaved]=useState(false);
  const [autoSaveMsg, setAutoSaveMsg]=useState(false);
  const [sessionGoal, setSessionGoal]=useState(0);
  const timerRef=useRef(null);
  const sessionStartPracticeRef=useRef(null); // 세션 시작 시점의 수행 분
  const t=T["수행가이드"];
  const todayRec=records[todayKey()]||{practice:0,baerae:0,cheongsu:{}};
  const todayRecRef=useRef(todayRec);
  useEffect(()=>{ todayRecRef.current=todayRec; },[todayRec]);

  const playAlarm = () => {
    try {
      const ctx = new (window.AudioContext || window.webkitAudioContext)();
      const notes = [880, 1100, 1320, 1100, 880];
      notes.forEach((freq, i) => {
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.connect(gain); gain.connect(ctx.destination);
        osc.type = "sine";
        osc.frequency.setValueAtTime(freq, ctx.currentTime + i * 0.22);
        gain.gain.setValueAtTime(0, ctx.currentTime + i * 0.22);
        gain.gain.linearRampToValueAtTime(0.35, ctx.currentTime + i * 0.22 + 0.05);
        gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.22 + 0.4);
        osc.start(ctx.currentTime + i * 0.22);
        osc.stop(ctx.currentTime + i * 0.22 + 0.5);
      });
    } catch(e) {}
  };

  const [alarmFired, setAlarmFired] = useState(false);

  useEffect(()=>{
    if(running) timerRef.current=setInterval(()=>setSec(s=>s+1),1000);
    else clearInterval(timerRef.current);
    return ()=>clearInterval(timerRef.current);
  },[running]);

  // 매 60초마다 자동저장
  useEffect(()=>{
    if(!running || sec===0 || sec%60!==0) return;
    const elapsed=Math.floor(sec/60);
    const base=sessionStartPracticeRef.current??0;
    onUpdateRecord(todayKey(),{...todayRecRef.current, practice:base+elapsed});
    setAutoSaveMsg(true); setTimeout(()=>setAutoSaveMsg(false),2500);
  },[sec]);

  useEffect(()=>{
    if(running && sessionGoal > 0 && sec === sessionGoal * 60 && !alarmFired) {
      playAlarm();
      setAlarmFired(true);
    }
    if(sec === 0) setAlarmFired(false);
  },[sec]);

  const stopTimer=async()=>{
    setRunning(false);
    const elapsed=Math.floor(sec/60);
    if(elapsed>0){
      const base=sessionStartPracticeRef.current??todayRecRef.current.practice;
      await onUpdateRecord(todayKey(),{...todayRecRef.current,practice:base+elapsed});
      setTimerSaved(true); setTimeout(()=>setTimerSaved(false),3000);
    }
    sessionStartPracticeRef.current=null;
    setSec(0);
  };

  const handleTimerToggle=()=>{
    if(!running && sec===0) {
      // 새 세션 시작: 현재 수행분 기록
      sessionStartPracticeRef.current=todayRecRef.current.practice;
    }
    setRunning(r=>!r);
  };

  const goalProgress=sessionGoal>0?Math.min(sec/(sessionGoal*60),1):0;
  const guide=GUIDE[lv];

  return (
    <div style={{background:t.bg,minHeight:"100vh",padding:"0 16px 100px"}}>
      {/* Timer */}
      <div style={{paddingTop:20,marginBottom:18}}>
        <div style={{background:"linear-gradient(135deg,#D1FAE5,#A7F3D0)",border:`1px solid ${t.accent}55`,borderRadius:24,padding:"22px 20px",textAlign:"center"}}>
          <p style={{color:"#065F46",fontSize:13,margin:"0 0 4px",fontWeight:600}}>🕯️ 수행 타이머</p>
          {/* Progress bar */}
          {sessionGoal>0&&(
            <div style={{background:"rgba(255,255,255,0.5)",borderRadius:6,height:8,margin:"8px 0",overflow:"hidden"}}>
              <div style={{width:`${goalProgress*100}%`,height:"100%",background:"#059669",borderRadius:6,transition:"width 0.5s"}}/>
            </div>
          )}
          <div style={{fontSize:52,fontWeight:800,color:"#065F46",letterSpacing:3,margin:"10px 0 16px",fontVariantNumeric:"tabular-nums"}}>
            {fmtTime(sec)}
          </div>
          {/* Timer controls */}
          <div style={{display:"flex",gap:10,justifyContent:"center",marginBottom:16}}>
            <button onClick={handleTimerToggle} style={{padding:"10px 22px",borderRadius:12,cursor:"pointer",fontWeight:700,fontSize:14,border:"none",background:running?"#FEE2E2":"#059669",color:running?"#EF4444":"#fff"}}>
              {running?"⏸ 일시정지":sec>0?"▶ 재개":"▶ 시작"}
            </button>
            {sec>0&&<button onClick={stopTimer} style={{padding:"10px 22px",borderRadius:12,cursor:"pointer",fontWeight:700,fontSize:14,border:"none",background:"#fff",color:"#059669"}}>⏹ 종료·저장</button>}
          </div>
          {timerSaved&&<p style={{color:"#059669",fontSize:13}}>✅ 기록에 저장됐어요!</p>}
          {autoSaveMsg&&<p style={{color:"#34D399",fontSize:12}}>💾 자동저장 완료</p>}

          {/* 10-min goal setter */}
          <div style={{background:"rgba(255,255,255,0.6)",borderRadius:14,padding:"12px 16px",marginTop:4}}>
            <p style={{color:"#065F46",fontSize:12,fontWeight:600,margin:"0 0 8px"}}>🎯 이번 수행 목표 시간</p>
            <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:12}}>
              <button onClick={()=>setSessionGoal(g=>Math.max(0,g-10))} style={{width:36,height:36,borderRadius:"50%",background:"#D1FAE5",border:"1.5px solid #059669",color:"#065F46",fontSize:18,fontWeight:700,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>−</button>
              <div style={{minWidth:70,textAlign:"center"}}>
                <span style={{fontSize:19,fontWeight:800,color:"#065F46"}}>{fmtMins(sessionGoal)}</span>
              </div>
              <button onClick={()=>setSessionGoal(g=>Math.min(240,g+10))} style={{width:36,height:36,borderRadius:"50%",background:"#D1FAE5",border:"1.5px solid #059669",color:"#065F46",fontSize:18,fontWeight:700,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>+</button>
            </div>
            {sessionGoal>0&&(
              <p style={{color:"#6EE7B7",fontSize:11,margin:"6px 0 0",textAlign:"center"}}>
                {sec<sessionGoal*60?`목표까지 ${fmtMins(Math.ceil((sessionGoal*60-sec)/60))} 남았어요`:"🎉 목표 달성!"}
              </p>
            )}
          </div>
        </div>
      </div>

      {/* 수행 가이드 */}
      <Sec title="📚 수행 가이드" bg={t.accentL} bc={t.accent}>
        <div style={{display:"flex",gap:8,marginBottom:14}}>
          {GUIDE.map((g,i)=>(
            <button key={i} onClick={()=>setLv(i)} style={{flex:1,padding:"8px 4px",borderRadius:10,cursor:"pointer",border:`1.5px solid ${lv===i?g.color:"#D1FAE5"}`,background:lv===i?`${g.color}22`:"#fff"}}>
              <div style={{fontSize:18}}>{g.emoji}</div>
              <div style={{fontSize:11,color:lv===i?g.color:"#9896AA",fontWeight:lv===i?700:400}}>{g.level}</div>
            </button>
          ))}
        </div>
          {guide.breathNote&&(
            <div style={{background:`${guide.color}15`,border:`1px solid ${guide.color}44`,borderRadius:10,padding:"10px 14px",marginBottom:12,display:"flex",alignItems:"center",gap:8}}>
              <span style={{fontSize:16}}>💨</span>
              <p style={{color:guide.color,fontSize:13,fontWeight:600,margin:0}}>{guide.breathNote}</p>
            </div>
          )}
          {guide.steps.map((s,i)=>(
            <div key={i} style={{display:"flex",gap:12,alignItems:"flex-start",marginBottom:10}}>
              <div style={{minWidth:26,height:26,borderRadius:"50%",background:`${guide.color}22`,border:`1.5px solid ${guide.color}`,display:"flex",alignItems:"center",justifyContent:"center",color:guide.color,fontSize:12,fontWeight:700,flexShrink:0}}>
                {i+1}
              </div>
              <div style={{paddingTop:2}}>
                <p style={{color:"#1F2937",fontSize:14,fontWeight:600,margin:"0 0 2px"}}>{s.name}</p>
                <p style={{color:"#6B7280",fontSize:13,lineHeight:1.6,margin:0}}>{s.desc}</p>
              </div>
            </div>
          ))}
      </Sec>

      {/* 배례 */}
    </div>
  );
}

function PlaylistCard({ url, sub, title, grad1, grad2 }) {
  return (
    <a href={url} target="_blank" rel="noreferrer"
      style={{display:"block",background:"#fff",borderRadius:16,overflow:"hidden",border:"1px solid #DBEAFE",marginBottom:14,textDecoration:"none",boxShadow:"0 3px 12px #DBEAFE"}}>
      <div style={{height:118,background:`linear-gradient(135deg,${grad1},${grad2})`,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:10,position:"relative"}}>
        {/* Playlist icon */}
        <div style={{width:54,height:54,borderRadius:"50%",background:"rgba(255,255,255,0.92)",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 4px 16px rgba(0,0,0,0.18)"}}>
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
            <rect x="3" y="5" width="14" height="2" rx="1" fill={grad1}/>
            <rect x="3" y="10" width="14" height="2" rx="1" fill={grad1}/>
            <rect x="3" y="15" width="9" height="2" rx="1" fill={grad1}/>
            <polygon points="17,11 23,14.5 17,18" fill={grad1}/>
          </svg>
        </div>
        {/* Badge */}
        <div style={{position:"absolute",bottom:8,right:10,background:"rgba(0,0,0,0.55)",borderRadius:6,padding:"3px 8px",display:"flex",alignItems:"center",gap:4}}>
          <svg width="14" height="10" viewBox="0 0 14 10"><rect width="14" height="10" rx="2" fill="#FF0000"/><polygon points="5.5,2.5 10.5,5 5.5,7.5" fill="white"/></svg>
          <span style={{color:"#fff",fontSize:10,fontWeight:600}}>Playlist</span>
        </div>
      </div>
      <div style={{padding:"11px 14px 14px"}}>
        {sub&&<span style={{fontSize:10,background:"#DBEAFE",color:"#1D4ED8",borderRadius:5,padding:"2px 8px",fontWeight:600,border:"1px solid #BFDBFE",marginBottom:6,display:"inline-block"}}>{sub}</span>}
        <p style={{color:"#1F2937",fontSize:13,fontWeight:600,lineHeight:1.55,margin:sub?"5px 0 0":"0"}}>{title}</p>
      </div>
    </a>
  );
}

/* ══════════════════════════════════════════════
   명상음악 TAB
══════════════════════════════════════════════ */
function YTCard({ id, title, sub, accent, bg, grad1, grad2 }) {
  const url = `https://youtu.be/${id}`;
  const g1 = grad1 || accent;
  const g2 = grad2 || bg;
  return (
    <a href={url} target="_blank" rel="noreferrer"
      style={{display:"block",background:"#fff",borderRadius:16,overflow:"hidden",border:`1px solid ${bg}`,marginBottom:14,textDecoration:"none",boxShadow:`0 3px 12px ${bg}`}}>
      {/* Visual header — gradient + play button, no external image needed */}
      <div style={{height:118,background:`linear-gradient(135deg,${g1},${g2})`,display:"flex",alignItems:"center",justifyContent:"center",position:"relative"}}>
        {/* Large play button circle */}
        <div style={{width:54,height:54,borderRadius:"50%",background:"rgba(255,255,255,0.92)",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 4px 16px rgba(0,0,0,0.18)"}}>
          <svg width="22" height="22" viewBox="0 0 22 22">
            <polygon points="7,4 19,11 7,18" fill={g1}/>
          </svg>
        </div>
        {/* YouTube badge */}
        <div style={{position:"absolute",bottom:8,right:10,background:"rgba(0,0,0,0.55)",borderRadius:6,padding:"3px 8px",display:"flex",alignItems:"center",gap:4}}>
          <svg width="14" height="10" viewBox="0 0 14 10"><rect width="14" height="10" rx="2" fill="#FF0000"/><polygon points="5.5,2.5 10.5,5 5.5,7.5" fill="white"/></svg>
          <span style={{color:"#fff",fontSize:10,fontWeight:600}}>YouTube</span>
        </div>
      </div>
      {/* Info */}
      <div style={{padding:"11px 14px 14px"}}>
        {sub&&<span style={{fontSize:10,background:`${accent}18`,color:accent,borderRadius:5,padding:"2px 8px",fontWeight:600,border:`1px solid ${accent}33`,marginBottom:6,display:"inline-block"}}>{sub}</span>}
        <p style={{color:"#1F2937",fontSize:13,fontWeight:600,lineHeight:1.55,margin:sub?"5px 0 0":"0"}}>{title}</p>
      </div>
    </a>
  );
}

